import os
import numpy as np


def safe_float(x):
    try:
        return float(x)
    except Exception:
        return x


def format_value(value):
    if isinstance(value, float):
        return f"{value:.6f}"
    return str(value)


def get_final_pair(metric_list):
    if not metric_list:
        return None, None
    epoch, value = metric_list[-1]
    return epoch, safe_float(value)


def get_best_loss_pair(loss_list):
    if not loss_list:
        return None, None
    best_epoch, best_value = min(loss_list, key=lambda t: t[1])
    return best_epoch, safe_float(best_value)


def print_metric(label, value):
    print(f"{label}: {format_value(value)}")


def summarize_selected_dataset(dataset_name, dataset_data):
    print(f"Dataset: {dataset_name}")

    selected_epochs = dataset_data.get("selected_epochs", None)
    if selected_epochs is not None:
        print_metric("selected source training epochs", selected_epochs)

    epoch_candidates = dataset_data.get("epoch_candidates", [])
    if epoch_candidates:
        print_metric("candidate source training epochs", epoch_candidates)

    metrics = dataset_data.get("metrics", {})
    losses = dataset_data.get("losses", {})

    train_acc_epoch, train_acc = get_final_pair(metrics.get("train", []))
    if train_acc is not None:
        print_metric("final train accuracy", train_acc)
        print_metric("epoch of final train accuracy", train_acc_epoch)

    val_acc_epoch, val_acc = get_final_pair(metrics.get("val", []))
    if val_acc is not None:
        print_metric("final validation accuracy", val_acc)
        print_metric("epoch of final validation accuracy", val_acc_epoch)

    train_loss_epoch, train_loss = get_final_pair(losses.get("train", []))
    if train_loss is not None:
        print_metric("final train loss", train_loss)
        print_metric("epoch of final train loss", train_loss_epoch)

    val_loss_epoch, val_loss = get_final_pair(losses.get("val", []))
    if val_loss is not None:
        print_metric("final validation loss", val_loss)
        print_metric("epoch of final validation loss", val_loss_epoch)

    best_val_loss_epoch, best_val_loss = get_best_loss_pair(losses.get("val", []))
    if best_val_loss is not None:
        print_metric("best validation loss", best_val_loss)
        print_metric("epoch of best validation loss", best_val_loss_epoch)

    test_metrics_list = metrics.get("test", [])
    if test_metrics_list:
        _, test_metric_dict = test_metrics_list[-1]
        if isinstance(test_metric_dict, dict):
            for key, value in test_metric_dict.items():
                explicit_name = key.replace("_", " ")
                print_metric(f"final test metric - {explicit_name}", safe_float(value))

    stream_results = dataset_data.get("stream_results", {})
    for mode_name, mode_metrics in stream_results.items():
        if isinstance(mode_metrics, dict):
            for metric_name, metric_value in mode_metrics.items():
                normalized_metric_name = (
                    metric_name.replace("_", " ").replace("-", " ").lower()
                )
                print_metric(
                    f"final {mode_name} stream {normalized_metric_name}",
                    safe_float(metric_value),
                )

    predictions = dataset_data.get("predictions", [])
    ground_truth = dataset_data.get("ground_truth", [])
    if predictions and ground_truth and len(predictions) == len(ground_truth):
        selected_gated_accuracy = float(
            np.mean(np.array(predictions) == np.array(ground_truth))
        )
        print_metric(
            "final selected gated stream accuracy from predictions",
            selected_gated_accuracy,
        )

    trials = dataset_data.get("trials", {})
    if trials:
        for trial_name, trial_data in trials.items():
            print(f"Dataset: {dataset_name} | Trial: {trial_name}")

            epochs_value = trial_data.get("epochs", None)
            if epochs_value is not None:
                print_metric("source training epochs", epochs_value)

            best_epoch = trial_data.get("best_epoch", None)
            if best_epoch is not None:
                print_metric("best checkpoint epoch", best_epoch)

            best_val_loss_trial = trial_data.get("best_val_loss", None)
            if best_val_loss_trial is not None:
                print_metric("best validation loss", safe_float(best_val_loss_trial))

            trial_metrics = trial_data.get("metrics", {})
            trial_losses = trial_data.get("losses", {})

            trial_train_acc_epoch, trial_train_acc = get_final_pair(
                trial_metrics.get("train", [])
            )
            if trial_train_acc is not None:
                print_metric("final train accuracy", trial_train_acc)
                print_metric("epoch of final train accuracy", trial_train_acc_epoch)

            trial_val_acc_epoch, trial_val_acc = get_final_pair(
                trial_metrics.get("val", [])
            )
            if trial_val_acc is not None:
                print_metric("final validation accuracy", trial_val_acc)
                print_metric("epoch of final validation accuracy", trial_val_acc_epoch)

            trial_train_loss_epoch, trial_train_loss = get_final_pair(
                trial_losses.get("train", [])
            )
            if trial_train_loss is not None:
                print_metric("final train loss", trial_train_loss)
                print_metric("epoch of final train loss", trial_train_loss_epoch)

            trial_val_loss_epoch, trial_val_loss = get_final_pair(
                trial_losses.get("val", [])
            )
            if trial_val_loss is not None:
                print_metric("final validation loss", trial_val_loss)
                print_metric("epoch of final validation loss", trial_val_loss_epoch)

            test_metrics = trial_data.get("test_metrics", {})
            for key, value in test_metrics.items():
                explicit_name = key.replace("_", " ")
                print_metric(f"final test metric - {explicit_name}", safe_float(value))

            trial_stream_results = trial_data.get("stream_results", {})
            for mode_name, mode_metrics in trial_stream_results.items():
                if isinstance(mode_metrics, dict):
                    for metric_name, metric_value in mode_metrics.items():
                        normalized_metric_name = (
                            metric_name.replace("_", " ").replace("-", " ").lower()
                        )
                        print_metric(
                            f"final {mode_name} stream {normalized_metric_name}",
                            safe_float(metric_value),
                        )

    print("-" * 80)


working_dir = os.path.join(os.getcwd(), "working")
experiment_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(experiment_path, allow_pickle=True).item()

for experiment_group_name, experiment_group_data in experiment_data.items():
