import os
import numpy as np


def safe_float(value):
    try:
        return float(value)
    except Exception:
        return value


def format_metric_value(value):
    if isinstance(value, float):
        return f"{value:.6f}"
    return str(value)


def print_metric(metric_name, value):
    print(f"{metric_name}: {format_metric_value(value)}")


def get_final_metric(metric_list):
    if not metric_list:
        return None
    return metric_list[-1][1]


def get_best_loss(loss_list):
    if not loss_list:
        return None
    return min(v for _, v in loss_list)


def analyze_source_training(exp_dict):
    train_metrics = exp_dict.get("metrics", {}).get("train", {})
    val_metrics = exp_dict.get("metrics", {}).get("val", {})
    train_losses = exp_dict.get("losses", {}).get("train", {})
    val_losses = exp_dict.get("losses", {}).get("val", {})

    lr_candidates = exp_dict.get("lr_candidates", [])
    best_lr = exp_dict.get("best_lr", None)
    best_val_loss = exp_dict.get("best_val_loss", None)
    lr_summary = exp_dict.get("lr_summary", [])

    print("Dataset: synthetic_reasoning_stream")
    print_metric(
        "best learning rate", safe_float(best_lr) if best_lr is not None else "N/A"
    )
    print_metric(
        "best validation loss",
        safe_float(best_val_loss) if best_val_loss is not None else "N/A",
    )

    if lr_summary:
        summary_map = {}
        for row in lr_summary:
            if len(row) >= 4:
                lr, best_vloss, final_train_acc, final_val_acc = row[:4]
                summary_map[f"lr_{lr:.0e}"] = {
                    "best_validation_loss": safe_float(best_vloss),
                    "final_train_accuracy": safe_float(final_train_acc),
                    "final_validation_accuracy": safe_float(final_val_acc),
                }
    else:
        summary_map = {}

    for lr in lr_candidates:
        lr_key = f"lr_{lr:.0e}"
        print(f"Dataset: synthetic_reasoning_stream ({lr_key})")

        final_train_acc = None
        final_val_acc = None
        final_train_loss = None
        final_val_loss = None
        best_validation_loss = None

        if lr_key in train_metrics:
            final_train_acc = get_final_metric(train_metrics[lr_key])
        if lr_key in val_metrics:
            final_val_acc = get_final_metric(val_metrics[lr_key])
        if lr_key in train_losses:
            final_train_loss = get_final_metric(train_losses[lr_key])
        if lr_key in val_losses:
            final_val_loss = get_final_metric(val_losses[lr_key])
            best_validation_loss = get_best_loss(val_losses[lr_key])

        if lr_key in summary_map:
            final_train_acc = summary_map[lr_key].get(
                "final_train_accuracy", final_train_acc
            )
            final_val_acc = summary_map[lr_key].get(
                "final_validation_accuracy", final_val_acc
            )
            best_validation_loss = summary_map[lr_key].get(
                "best_validation_loss", best_validation_loss
            )

        print_metric(
            "final train accuracy",
            safe_float(final_train_acc) if final_train_acc is not None else "N/A",
        )
        print_metric(
            "final validation accuracy",
            safe_float(final_val_acc) if final_val_acc is not None else "N/A",
        )
        print_metric(
            "final train loss",
            safe_float(final_train_loss) if final_train_loss is not None else "N/A",
        )
        print_metric(
            "final validation loss",
            safe_float(final_val_loss) if final_val_loss is not None else "N/A",
        )
        print_metric(
            "best validation loss",
            (
                safe_float(best_validation_loss)
                if best_validation_loss is not None
                else "N/A"
            ),
        )


def analyze_stream_results(exp_dict):
    stream_results = exp_dict.get("stream_results", {})

    for mode_name, mode_results in stream_results.items():
        print(f"Dataset: synthetic_reasoning_stream ({mode_name} stream evaluation)")
        if "Shifted-Stream Accuracy" in mode_results:
            print_metric(
                "shifted-stream accuracy",
                safe_float(mode_results["Shifted-Stream Accuracy"]),
            )
        if "trigger_rate" in mode_results:
            print_metric(
                "adaptation trigger rate", safe_float(mode_results["trigger_rate"])
            )


def analyze_test_summary(exp_dict):
    test_metrics = exp_dict.get("metrics", {}).get("test", [])
    if not test_metrics:
        return

    _, test_summary = test_metrics[-1]
    print("Dataset: synthetic_reasoning_stream (test summary)")

    if isinstance(test_summary, dict):
        if "best_lr" in test_summary:
            print_metric("best learning rate", safe_float(test_summary["best_lr"]))
        if "best_val_loss" in test_summary:
            print_metric(
                "best validation loss", safe_float(test_summary["best_val_loss"])
            )
        if "frozen_acc" in test_summary:
            print_metric(
                "frozen shifted-stream accuracy", safe_float(test_summary["frozen_acc"])
            )
        if "always_acc" in test_summary:
            print_metric(
                "always-adapt shifted-stream accuracy",
                safe_float(test_summary["always_acc"]),
            )
        if "gated_acc" in test_summary:
            print_metric(
                "gated-adapt shifted-stream accuracy",
                safe_float(test_summary["gated_acc"]),
            )


def analyze_saved_predictions(exp_dict):
    preds = np.array(exp_dict.get("predictions", []))
    gt = np.array(exp_dict.get("ground_truth", []))

    print("Dataset: synthetic_reasoning_stream (saved gated predictions)")
    if preds.size == 0 or gt.size == 0 or preds.shape != gt.shape:
        print_metric("gated shifted-stream accuracy from saved predictions", "N/A")
        return

    accuracy = float((preds == gt).mean())
    print_metric("gated shifted-stream accuracy from saved predictions", accuracy)


working_dir = os.path.join(os.getcwd(), "working")
experiment_data_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(experiment_data_path, allow_pickle=True).item()

for experiment_name, datasets in experiment_data.items():
    for dataset_name, exp_dict in datasets.items():
        analyze_source_training(exp_dict)
        analyze_stream_results(exp_dict)
        analyze_test_summary(exp_dict)
