        return "None"
    if isinstance(value, (float, np.floating)):
        return f"{float(value):.6f}"
    return str(value)


def print_dataset_metrics(method_name, dataset_name, dataset_record):
    print(f"Dataset: {dataset_name}")

    metrics = dataset_record.get("metrics", {})
    losses = dataset_record.get("losses", {})
    stream_results = dataset_record.get("stream_results", {})

    final_train_accuracy = get_last_scalar_from_pairs(metrics.get("train", []))
    final_validation_accuracy = get_last_scalar_from_pairs(metrics.get("val", []))

    final_train_loss = get_last_scalar_from_pairs(losses.get("train", []))
    final_validation_loss = get_last_scalar_from_pairs(losses.get("val", []))

    print(f"Method name: {method_name}")
    print(f"Final train accuracy: {format_value(final_train_accuracy)}")
    print(f"Final validation accuracy: {format_value(final_validation_accuracy)}")
    print(f"Final train loss: {format_value(final_train_loss)}")
    print(f"Final validation loss: {format_value(final_validation_loss)}")

    test_entries = metrics.get("test", [])
    if test_entries:
        _, test_info = test_entries[-1]
        if isinstance(test_info, dict):
            print(
                f"Final frozen shifted-stream accuracy: {format_value(test_info.get('frozen_acc'))}"
            )
            print(
                f"Final always-adapt shifted-stream accuracy: {format_value(test_info.get('always_acc'))}"
            )
            print(
                f"Final best gated shifted-stream accuracy: {format_value(test_info.get('best_gated_acc'))}"
            )
            print(
                f"Best entropy threshold: {format_value(test_info.get('best_entropy_thresh'))}"
            )

    if stream_results:
        frozen_result = stream_results.get("frozen", {})
        always_result = stream_results.get("always", {})
        gated_best_result = stream_results.get("gated_best", {})

        if frozen_result:
            print(
                f"Frozen shifted-stream accuracy: "
                f"{format_value(frozen_result.get('Shifted-Stream Accuracy'))}"
            )
            print(
                f"Frozen adaptation trigger rate: "
                f"{format_value(frozen_result.get('trigger_rate'))}"
            )

        if always_result:
            print(
                f"Always-adapt shifted-stream accuracy: "
                f"{format_value(always_result.get('Shifted-Stream Accuracy'))}"
            )
            print(
                f"Always-adapt trigger rate: "
                f"{format_value(always_result.get('trigger_rate'))}"
            )

        if gated_best_result:
            print(
                f"Best gated shifted-stream accuracy: "
                f"{format_value(gated_best_result.get('Shifted-Stream Accuracy'))}"
            )
            print(
                f"Best gated trigger rate: "
                f"{format_value(gated_best_result.get('trigger_rate'))}"
            )
            print(
                f"Best gated entropy threshold: "
                f"{format_value(gated_best_result.get('entropy_thresh'))}"
            )

    threshold_grid = dataset_record.get("threshold_grid", [])
    threshold_accuracies = dataset_record.get("threshold_accuracies", [])
    threshold_trigger_rates = dataset_record.get("threshold_trigger_rates", [])

    if threshold_grid and threshold_accuracies:
        best_idx = int(np.argmax(np.array(threshold_accuracies)))
        print(
            f"Best threshold tuning accuracy: {format_value(threshold_accuracies[best_idx])}"
        )
        print(
            f"Best threshold tuning threshold: {format_value(threshold_grid[best_idx])}"
        )
        if best_idx < len(threshold_trigger_rates):
            print(
                f"Best threshold tuning trigger rate: "
                f"{format_value(threshold_trigger_rates[best_idx])}"
            )

    print()


